func (a *CustomerFBOAccount) GetSubAccountForRoute(ctx context.Context, params ledger.CustomerFBORouteParams) (ledger.SubAccount, error) {
	if err := params.Validate(); err != nil {
		return nil, err
	}
	return a.services.SubAccountService.EnsureSubAccount(ctx, ledger.CreateSubAccountInput{
		Namespace: a.data.ID.Namespace,
		AccountID: a.data.ID.ID,
		Route:     params.Route(),
	})
}

switch record.Kind {
case ledger.BreakageKindPlan, ledger.BreakageKindReopen:
	group.amount = group.amount.Add(record.Amount)
	if record.Kind == ledger.BreakageKindPlan && (group.cursorID.ID == "" || record.ID.ID < group.cursorID.ID) {
		group.cursorID = record.ID
	}
case ledger.BreakageKindRelease:
	group.amount = group.amount.Sub(record.Amount)
}
