for idx, txInput := range txInputs {
	if err := ledger.ValidateTransactionInputWith(ctx, txInput, l.routingValidator); err != nil {
		return nil, fmt.Errorf("validate tx %d: %w", idx, err)
	}
}
return transaction.Run(ctx, l.repo, func(ctx context.Context) (*TransactionGroup, error) {
	if err := l.lockAccountsForTransactionInputs(ctx, group.Namespace(), txInputs); err != nil {
		return nil, err
	}
	txG, _ := l.repo.CreateTransactionGroup(ctx, CreateTransactionGroupInput{Namespace: group.Namespace(), Annotations: group.Annotations()})
	txGroup := &TransactionGroup{data: txG}
	for _, txInput := range txInputs {
		tx, _ := l.repo.BookTransaction(ctx, models.NamespacedID{Namespace: group.Namespace(), ID: txG.ID}, txInput)
		txGroup.transactions = append(txGroup.transactions, tx)
	}
	return txGroup, nil
})

return transaction.Run(ctx, s.Repo, func(ctx context.Context) (ledger.CustomerAccounts, error) {
	if err := s.lockCustomerProvisioning(ctx, customerID); err != nil {
		return ledger.CustomerAccounts{}, err
	}
	accountIDs, _ := s.Repo.GetCustomerAccountIDs(ctx, customerID)
	for _, accountType := range ledger.CustomerAccountTypes {
		if _, ok := accountIDs[accountType]; ok { continue }
		acc, _ := s.AccountService.CreateAccount(ctx, ledgeraccount.CreateAccountInput{Namespace: customerID.Namespace, Type: accountType})
		if err := s.Repo.CreateCustomerAccount(ctx, CreateCustomerAccountInput{CustomerID: customerID, AccountType: accountType, AccountID: acc.ID().ID}); err != nil {
			if existingErr, ok := AsCustomerAccountAlreadyExistsError(err); ok { accountIDs[accountType] = existingErr.AccountID; continue }
			return ledger.CustomerAccounts{}, err
		}
	}
	return s.GetCustomerAccounts(ctx, customerID)
})

func (t TransferCustomerReceivableToAccruedTemplate) resolve(ctx context.Context, customerID customer.CustomerID, resolvers ResolverDependencies) (ledger.TransactionInput, error) {
	customerAccounts, err := resolvers.AccountService.GetCustomerAccounts(ctx, customerID)
	if err != nil { return nil, err }
	receivable, _ := customerAccounts.ReceivableAccount.GetSubAccountForRoute(ctx, ledger.CustomerReceivableRouteParams{Currency: t.Currency, CostBasis: t.CostBasis, TransactionAuthorizationStatus: ledger.TransactionAuthorizationStatusOpen})
	accrued, _ := customerAccounts.AccruedAccount.GetSubAccountForRoute(ctx, ledger.CustomerAccruedRouteParams{Currency: t.Currency, TaxCode: t.TaxCode, TaxBehavior: t.TaxBehavior, CostBasis: t.CostBasis})
	return &TransactionInput{bookedAt: t.At, entryInputs: []*EntryInput{
		{address: receivable.Address(), amount: t.Amount.Neg()},
		{address: accrued.Address(), amount: t.Amount},
	}}, nil
}
